import fast_hadamard_transform
import glog
import torch

from lib import utils


def get_hadK(n, transpose=False):
    hadK, K = None, None
    if n % 172 == 0:  # llama-2-7b up
        assert (is_pow2(n // 172))
        K = 172
        hadK = get_had172().T if transpose else get_had172()
    elif n % 156 == 0:  # llama-1-30b 3x hidden
        assert (is_pow2(n // 156))
        K = 156
        hadK = get_had156().T if transpose else get_had156()
    elif n % 140 == 0:  # llama-1-30b intermediate
        assert (is_pow2(n // 140))
        K = 140
        hadK = get_had140().T if transpose else get_had140()
    elif n % 136 == 0:
        assert(is_pow2(n // 136))
        K = 136
        hadK = get_had136().T if transpose else get_had136()
    elif n % 124 == 0:  # falcon 180b
        assert (is_pow2(n // 124))
        K = 124
        hadK = get_had124().T if transpose else get_had124()
    elif n % 116 == 0:  # falcon 180b
        assert (is_pow2(n // 116))
        K = 116
        hadK = get_had116().T if transpose else get_had116()
    elif n % 108 == 0:  # llama-1-13b intermediate
        assert (is_pow2(n // 108))
        K = 108
        hadK = get_had108().T if transpose else get_had108()
    elif n % 100 == 0: # Qwen3-32B intermediate
        assert (is_pow2(n // 100))
        K = 100
        hadK = get_had100().T if transpose else get_had100()
    elif n % 76 == 0:  
        assert (is_pow2(n // 76))
        K = 76
        hadK = get_had76().T if transpose else get_had76()
    elif n % 60 == 0:  # llama-1-13b 3x hidden
        assert (is_pow2(n // 60))
        K = 60
        hadK = get_had60().T if transpose else get_had60()
    elif n % 52 == 0:  # llama-1-13b 1x hidden
        assert (is_pow2(n // 52))
        K = 52
        hadK = get_had52().T if transpose else get_had52()
    elif n % 36 == 0:
        assert (is_pow2(n // 36))
        K = 36
        hadK = get_had36().T if transpose else get_had36()
    elif n % 28 == 0:
        assert (is_pow2(n // 28))
        K = 28
        hadK = get_had28().T if transpose else get_had28()
    elif n % 20 == 0:
        assert (is_pow2(n // 20))
        K = 20
        hadK = get_had20().T if transpose else get_had20()
    elif n % 12 == 0:
        assert (is_pow2(n // 12))
        K = 12
        hadK = get_had12().T if transpose else get_had12()
    else:
        assert (is_pow2(n))
        K = 1

    return hadK, K


def matmul_hadU(X, transpose=False, block_size=64):
    n = X.shape[-1]
    
    # First check if dimension is supported
    if not can_use_standard_hadamard(n):
        glog.warning(f"Dimension {n} not supported by standard Hadamard. Using blockwise method (block_size={block_size}).")
        return matmul_hadU_blockwise(X, block_size=block_size, transpose=transpose)
    
    # Try standard Hadamard transform
    try:
        hadK, K = get_hadK(n, transpose)
    except (AssertionError, Exception) as e:
        glog.warning(f"Failed to get Hadamard matrix for dimension {n}: {e}. Falling back to blockwise method.")
        return matmul_hadU_blockwise(X, block_size=block_size, transpose=transpose)
    
    input = X.clone().view(-1, n, 1)
    output = input.clone()
    while input.shape[1] > K:
        input = input.view(input.shape[0], input.shape[1] // 2, 2,
                           input.shape[2])
        output = output.view(input.shape)
        output[:, :, 0, :] = input[:, :, 0, :] + input[:, :, 1, :]
        output[:, :, 1, :] = input[:, :, 0, :] - input[:, :, 1, :]
        output = output.view(input.shape[0], input.shape[1], -1)
        (input, output) = (output, input)
    del output
    utils.clean()
    if K > 1:
        input = torch.bmm(
            hadK.repeat(len(input), 1, 1).to(input.device).to(input.dtype),
            input)
    return input.view(X.shape) / torch.tensor(n).sqrt()


def matmul_hadUt(X, block_size=64):
    return matmul_hadU(X, transpose=True, block_size=block_size)


def is_pow2(n):
    """检查n是否为2的幂"""
    return n > 0 and (n & (n - 1)) == 0


def can_use_standard_hadamard(n):
    """检查维度n是否支持标准Hadamard变换（在get_hadK中定义的所有情况）"""
    # 必须包含 get_hadK 中的所有因子
    factors = [172, 156, 140, 136, 124, 116, 108, 100, 76, 60, 52, 36, 28, 20, 12]
    
    # 检查是否是预定义因子的倍数
    for factor in factors:
        if n % factor == 0 and is_pow2(n // factor):
            return True
    
    # 检查是否本身是2的幂
    if is_pow2(n):
        return True
    
    return False


def get_largest_pow2_factor(n):
    """
    获取n中最大的2的幂次因子
    例如：
    - 1408 = 11 × 128 → 返回 128
    - 10944 = 171 × 64 → 返回 64
    - 1024 = 1 × 1024 → 返回 1024
    """
    if is_pow2(n):
        return n
    
    # 提取n中所有的2的因数
    pow2_factor = 1
    temp = n
    while temp % 2 == 0:
        pow2_factor *= 2
        temp //= 2
    return pow2_factor


def apply_hadamard_blockwise(X, block_size=64):
    """
    对矩阵X的最后一个维度应用分块Hadamard变换
    
    参数：
    X: 张量 e.g. (m, n)
    block_size: Hadamard变换块的大小（必须是2的幂）
    
    返回：
    变换后的张量，形状不变
    SU: 对角缩放向量（用于反向变换）
    """
    assert is_pow2(block_size), f"block_size must be power of 2, got {block_size}"
    
    device = X.device
    dtype = X.dtype
    original_shape = X.shape
    
    # 处理最后一个维度
    n = original_shape[-1]
    
    # 如果n已经是2的幂且小于等于block_size，直接使用matmul_hadU
    if is_pow2(n) and n <= block_size:
        hadX = matmul_hadU(X)
        SU = torch.ones(n, dtype=torch.float32, device='cpu')
        return hadX, SU
    
    # 否则进行分块变换
    num_blocks = (n + block_size - 1) // block_size
    
    # 填充到整数个块
    padded_n = num_blocks * block_size
    if n < padded_n:
        pad_size = padded_n - n
        X_padded = torch.nn.functional.pad(X, (0, pad_size))
    else:
        X_padded = X
    
    # reshape成分块形式
    new_shape = list(original_shape[:-1]) + [num_blocks, block_size]
    X_blocks = X_padded.view(*new_shape)
    
    # 对每个块应用快速Hadamard变换
    hadX_blocks = torch.zeros_like(X_blocks)
    for i in range(num_blocks):
        block = X_blocks[..., i, :]  # shape: (..., block_size)
        # 使用fast_hadamard_transform库
        had_block = fast_hadamard_transform.hadamard_transform(block, scale=False)
        hadX_blocks[..., i, :] = had_block
    
    # reshape回原始形状并去除填充
    hadX = hadX_blocks.reshape(*original_shape[:-1], -1)
    hadX = hadX[..., :n]
    
    # 缩放（Hadamard变换通常要除以sqrt(n_block)）
    scale_factor = torch.tensor(block_size, dtype=dtype, device=device).sqrt()
    hadX = hadX / scale_factor
    
    # 返回缩放向量（全1表示没有额外的对角缩放）
    SU = torch.ones(n, dtype=torch.float32, device='cpu')
    
    return hadX, SU


def apply_hadamard_blockwise_inv(X, block_size=64):
    """
    对矩阵X的最后一个维度应用逆向分块Hadamard变换
    
    参数：
    X: 张量 e.g. (m, n)
    block_size: Hadamard变换块的大小（必须是2的幂）
    
    返回：
    反向变换后的张量，形状不变
    """
    assert is_pow2(block_size), f"block_size must be power of 2, got {block_size}"
    
    device = X.device
    dtype = X.dtype
    original_shape = X.shape
    
    # 处理最后一个维度
    n = original_shape[-1]
    
    # 如果n已经是2的幂且小于等于block_size，使用matmul_hadU（自逆性质）
    if is_pow2(n) and n <= block_size:
        return matmul_hadU(X)
    
    # 否则进行分块反向变换
    num_blocks = (n + block_size - 1) // block_size
    
    # 填充到整数个块
    padded_n = num_blocks * block_size
    if n < padded_n:
        pad_size = padded_n - n
        X_padded = torch.nn.functional.pad(X, (0, pad_size))
    else:
        X_padded = X
    
    # reshape成分块形式
    new_shape = list(original_shape[:-1]) + [num_blocks, block_size]
    X_blocks = X_padded.view(*new_shape)
    
    # 对每个块应用逆向Hadamard变换（Hadamard是自逆的）
    hadX_blocks = torch.zeros_like(X_blocks)
    for i in range(num_blocks):
        block = X_blocks[..., i, :]  # shape: (..., block_size)
        # 使用fast_hadamard_transform库（Hadamard变换是自逆的）
        had_block = fast_hadamard_transform.hadamard_transform(block, scale=False)
        hadX_blocks[..., i, :] = had_block
    
    # reshape回原始形状并去除填充
    hadX = hadX_blocks.reshape(*original_shape[:-1], -1)
    hadX = hadX[..., :n]
    
    # 缩放（Hadamard变换通常要除以sqrt(n_block)）
    scale_factor = torch.tensor(block_size, dtype=dtype, device=device).sqrt()
    hadX = hadX / scale_factor
    
    return hadX


def matmul_hadU_blockwise(X, block_size=64, transpose=False):
    """
    使用 blockwise 方法对矩阵应用 Hadamard 变换
    当标准方法不支持时作为回退方案
    
    参数：
    X: 输入张量
    block_size: 块大小（必须是2的幂）
    transpose: 是否转置 (当前未使用，保留用于接口兼容)
    
    返回：
    变换后的张量
    """
    n = X.shape[-1]
    
    # 直接使用 blockwise 方法（不再检查是否支持标准方法，避免循环调用）
    glog.info(f"Using blockwise Hadamard (block_size={block_size}) for dimension {n}")
    hadX, _ = apply_hadamard_blockwise(X, block_size=block_size)
    return hadX


def matmul_hadUt_blockwise(X, block_size=64):
    """
    使用 blockwise 方法对矩阵应用转置 Hadamard 变换
    当标准方法不支持时作为回退方案
    """
    return matmul_hadU_blockwise(X, block_size=block_size, transpose=True)


torch.library.define("quip_lib::hadamard", "(Tensor x, float scale) -> Tensor")

@torch.library.impl_abstract("quip_lib::hadamard")
def hadamard_abstract(x: torch.Tensor, scale: float) -> torch.Tensor:
    return x

@torch.library.impl("quip_lib::hadamard", "default")
def hadamard(x: torch.Tensor, scale: float) -> torch.Tensor:
    return fast_hadamard_transform.hadamard_transform(x, scale)


def matmul_hadU_cuda(X, hadK, K, transpose=False, block_size=64):
    n = X.shape[-1]
    
    # If hadK is None, use blockwise Hadamard (for unsupported dimensions)
    if hadK is None:
        glog.warning(f"hadK is None for dimension {n}, using blockwise Hadamard (block_size={block_size})")
        return matmul_hadU_blockwise(X, block_size=block_size, transpose=transpose)
    
    if K == 1:
        return torch.ops.quip_lib.hadamard(X.contiguous(), 1/(n**0.5))

    if transpose:
        hadK = hadK.T.contiguous()
    input = X.float().view(-1, K, n // K)
    input = torch.ops.quip_lib.hadamard(input.contiguous(), 1/(n**0.5))
    input = hadK.to(input.device).to(input.dtype) @ input
    return input.to(X.device).to(X.dtype).reshape(X.shape)
 

def matmul_hadUt_cuda(X, hadK, K, block_size=64):
    return matmul_hadU_cuda(X, hadK, K, transpose=True, block_size=block_size)

def is_pow2(n):
    return (n & (n - 1) == 0) and (n > 0)

def transform_symbol_to_list(symbol: str, K: int):
    seq = [1 if c == '+' else -1 for c in symbol if c in '+-']
    if len(seq) % K != 0:
        raise ValueError(f"Length {len(seq)} not divisible by K={K}. Check line breaks.")
    return [seq[i:i+K] for i in range(0, len(seq), K)]

